import { initCharts } from './charts.js';

document.addEventListener('DOMContentLoaded', async () => {
    try {
        // Load data generated by Python pipeline
        const response = await fetch('./assets/data/dashboard_data.json');
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        
        const data = await response.json();
        
        // Hide loader, show dashboard
        document.getElementById('loading').classList.add('hidden');
        document.getElementById('dashboard-content').classList.remove('hidden');

        // Render data
        renderKPIs(data);
        renderDemographics(data);
        renderLogisticModel(data);
        
        // Initialize charts module
        initCharts(data);

    } catch (error) {
        console.error("Error cargando los datos del dashboard:", error);
        document.getElementById('loading').innerHTML = `
            <div class="text-red-500 text-center">
                <svg class="w-12 h-12 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                <p class="font-semibold">Error al cargar los datos procesados.</p>
                <p class="text-sm">Asegúrese de ejecutar el pipeline de Python primero.</p>
            </div>
        `;
    }
});

function renderKPIs(data) {
    const kpis = data.kpis;
    document.getElementById('kpi-tasa').innerText = `${kpis.tasa_global}%`;
    document.getElementById('kpi-usuarios').innerText = kpis.total_usuarios.toLocaleString('es-PY');
    document.getElementById('kpi-brecha-ur').innerText = `${kpis.brecha_urb_rur} pp`;
    document.getElementById('kpi-poblacion').innerText = kpis.total_poblacion.toLocaleString('es-PY');
    
    if (data.metadata?.fecha_actualizacion) {
        document.getElementById('badge-fecha').innerText = `Actualizado: ${data.metadata.fecha_actualizacion}`;
    }
}

function renderDemographics(data) {
    const p = data.perfil_demografico.edad_promedio;
    document.getElementById('edad-usr').innerText = p.usuarios;
    document.getElementById('edad-nousr').innerText = p.no_usuarios;
}

function renderLogisticModel(data) {
    const modelo = data.modelo;
    const tbody = document.getElementById('cuerpo-tabla-modelo');
    
    if (modelo.status !== "success") {
        tbody.innerHTML = `<tr><td colspan="4" class="px-6 py-4 text-center text-red-500">Error en ajuste del modelo logístico</td></tr>`;
        return;
    }

    // Sort by odds ratio descending
    const factores = modelo.factores.sort((a,b) => b.odds_ratio - a.odds_ratio);

    tbody.innerHTML = factores.map((f, i) => {
        const rowBg = i % 2 === 0 ? "bg-white" : "bg-gray-50";
        const impactText = f.odds_ratio > 1 ? "Promotor" : "Barrera";
        const impactColor = f.odds_ratio > 1 ? "text-green-600 font-semibold" : "text-amber-600 font-semibold";
        const sigBadge = f.significativo 
            ? `<span class="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-green-100 text-green-800">Sí</span>`
            : `<span class="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 text-gray-800">No</span>`;

        return `
            <tr class="${rowBg}">
                <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-medium">${f.variable}</td>
                <td class="px-6 py-4 whitespace-nowrap text-sm text-right ${impactColor}">${f.odds_ratio.toFixed(2)}x</td>
                <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500 text-right">${f.p_valor.toFixed(4)}</td>
                <td class="px-6 py-4 whitespace-nowrap text-center">${sigBadge}</td>
            </tr>
        `;
    }).join('');
}
